// Récupération des paramètres
const body = $input.first().json.body || $input.first().json;
const { action, username, password, filename, content } = body;
const folder = 'Mentoria';

if (!username || !password) {
  return [{ json: { success: false, error: 'Identifiants manquants' } }];
}

const baseUrl = `https://nuage.apps.education.fr/remote.php/dav/files/${encodeURIComponent(username)}/${folder}/`;
const auth = 'Basic ' + Buffer.from(`${username}:${password}`).toString('base64');

const req = async (method, url, reqBody, contentType) => {
  const options = {
    method,
    url,
    headers: {
      'Authorization': auth,
      ...(contentType ? { 'Content-Type': contentType } : {}),
      ...(method === 'PROPFIND' ? { 'Depth': '1' } : {})
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (reqBody) options.body = reqBody;
  return await this.helpers.httpRequest(options);
};

try {
  // TEST : vérifie les identifiants et crée le dossier Mentoria si besoin
  if (action === 'test') {
    const r = await req('PROPFIND', `https://nuage.apps.education.fr/remote.php/dav/files/${encodeURIComponent(username)}/`, '<?xml version="1.0"?><d:propfind xmlns:d="DAV:"><d:prop><d:displayname/></d:prop></d:propfind>', 'application/xml');
    if (r.statusCode === 401) return [{ json: { success: false, error: 'Identifiants invalides — vérifiez votre mot de passe d\'application.' } }];
    if (r.statusCode === 207 || r.statusCode === 200) {
      // Crée le dossier Mentoria (ignore l'erreur 405 si existe déjà)
      await req('MKCOL', baseUrl, null, null);
      return [{ json: { success: true, action: 'test' } }];
    }
    return [{ json: { success: false, error: 'Erreur connexion: ' + r.statusCode } }];
  }

  // LISTE : retourne les fichiers bot_*.json
  if (action === 'list') {
    const xmlBody = '<?xml version="1.0"?><d:propfind xmlns:d="DAV:"><d:prop><d:displayname/></d:prop></d:propfind>';
    const r = await req('PROPFIND', baseUrl, xmlBody, 'application/xml');
    const xml = typeof r.body === 'string' ? r.body : '';
    const files = [];
    const re = /<[dD]:href[^>]*>([^<]+)<\/[dD]:href>/g;
    let m;
    while ((m = re.exec(xml)) !== null) {
      const name = decodeURIComponent(m[1]).split('/').filter(Boolean).pop();
      if (name && name.startsWith('bot_') && name.endsWith('.json')) files.push({ name });
    }
    return [{ json: { success: true, files } }];
  }

  // LECTURE
  if (action === 'read') {
    const r = await req('GET', baseUrl + encodeURIComponent(filename), null, null);
    if (r.statusCode === 404) return [{ json: { success: false, error: 'Fichier introuvable' } }];
    const parsed = typeof r.body === 'string' ? JSON.parse(r.body) : r.body;
    return [{ json: { success: true, content: parsed } }];
  }

  // ÉCRITURE
  if (action === 'write') {
    const data = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    await req('PUT', baseUrl + encodeURIComponent(filename), data, 'application/json');
    return [{ json: { success: true, action: 'write' } }];
  }

  // SUPPRESSION
  if (action === 'delete') {
    await req('DELETE', baseUrl + encodeURIComponent(filename), null, null);
    return [{ json: { success: true, action: 'delete' } }];
  }

  return [{ json: { success: false, error: 'Action inconnue: ' + action } }];

} catch(e) {
  return [{ json: { success: false, error: e.message } }];
}
